                        <td className={`px-4 py-3 text-sm ${isReserved ? 'text-slate-400 italic' : 'text-slate-700'}`}>
                          {item.assetName}
                        </td>
                        <td className="px-4 py-3 font-mono text-xs text-slate-500 max-w-xs truncate">
