   103→
   104→// Calculate free static IPs (only in static range .171-.254, excluding assigned ones)
   105→const calculateFreeStaticIPs = () => {
   106→  const usedIPs = new Set(ipData.map(item => {
   107→    const parts = item.ip.split('.');
   108→    return parseInt(parts[3]);
   109→  }));
   110→
   111→  const freeIPs = [];
   112→  // Only check static range (171-254)
   113→  for (let i = NETWORK_CONFIG.staticStart; i <= NETWORK_CONFIG.staticEnd; i++) {
   114→    if (!usedIPs.has(i)) {
   115→      freeIPs.push(`192.168.0.${i}`);
   116→    }
   117→  }
   118→  return freeIPs;
   119→};
   120→
   121→// Group consecutive IPs into ranges for cleaner display
   122→const groupIPsIntoRanges = (ips) => {
   123→  if (ips.length === 0) return [];
   124→
   125→  const ranges = [];
   126→  let rangeStart = parseInt(ips[0].split('.')[3]);
   127→  let rangeEnd = rangeStart;
   128→
   129→  for (let i = 1; i < ips.length; i++) {
   130→    const current = parseInt(ips[i].split('.')[3]);
   131→    if (current === rangeEnd + 1) {
   132→      rangeEnd = current;
   133→    } else {
   134→      ranges.push({ start: rangeStart, end: rangeEnd });
   135→      rangeStart = current;
   136→      rangeEnd = current;
   137→    }
   138→  }
   139→  ranges.push({ start: rangeStart, end: rangeEnd });
   140→
   141→  return ranges;
   142→};
   143→
   144→// Get unique values for filters
   145→const getUniqueValues = (data, key) => {
   146→  const values = [...new Set(data.map(item => item[key]).filter(Boolean))];
   147→  return values.sort();
   148→};
   149→
   150→// Get icon for app/service type
   151→const getServiceIcon = (apps, assetName) => {
   152→  const combined = `${apps} ${assetName}`.toLowerCase();
   153→  if (combined.includes('camera') || combined.includes('reolink') || combined.includes('tapo')) return Camera;
   154→  if (combined.includes('proxmox')) return Server;
   155→  if (combined.includes('docker')) return Box;
   156→  if (combined.includes('pihole') || combined.includes('dns')) return Shield;
   157→  if (combined.includes('nas') || combined.includes('truenas') || combined.includes('synology')) return HardDrive;
   158→  if (combined.includes('unifi') || combined.includes('wifi') || combined.includes('access point')) return Wifi;
   159→  if (combined.includes('ghost') || combined.includes('blog') || combined.includes('nginx')) return Globe;
   160→  if (combined.includes('switch') || combined.includes('mikrotik') || combined.includes('netgear')) return Monitor;
   161→  return Cpu;
   162→};
