   189→// Check if IP is in DHCP range
   190→const isInDHCPRange = (ip) => {
   191→  const lastOctet = parseInt(ip.split('.')[3]);
   192→  return lastOctet >= NETWORK_CONFIG.dhcpStart && lastOctet <= NETWORK_CONFIG.dhcpEnd;
   193→};
   194→
   195→// Check if IP is a fixed address within DHCP range
   196→const isFixedInDHCP = (ip) => {
   197→  const lastOctet = parseInt(ip.split('.')[3]);
   198→  return NETWORK_CONFIG.fixedInDHCP.includes(lastOctet);
