const calculateFreeIPs = () => {
  const usedIPs = new Set(ipData.map(item => {
    const parts = item.ip.split('.');
    return parseInt(parts[3]);
  }));

  const freeIPs = [];
  // Check range 1-254 (excluding 0 for network and 255 for broadcast)
  for (let i = 1; i <= 254; i++) {
    if (!usedIPs.has(i)) {
      freeIPs.push(`192.168.0.${i}`);
    }
  }
  return freeIPs;
};

// Group consecutive IPs into ranges for cleaner display
const groupIPsIntoRanges = (ips) => {
  if (ips.length === 0) return [];

  const ranges = [];
  let rangeStart = parseInt(ips[0].split('.')[3]);
  let rangeEnd = rangeStart;

  for (let i = 1; i < ips.length; i++) {
    const current = parseInt(ips[i].split('.')[3]);
    if (current === rangeEnd + 1) {
      rangeEnd = current;
    } else {
      ranges.push({ start: rangeStart, end: rangeEnd });
      rangeStart = current;
      rangeEnd = current;
    }
  }
  ranges.push({ start: rangeStart, end: rangeEnd });

  return ranges;
};

