                </span>
              </div>
            </div>
          </div>

          {/* Stats Bar */}
          <div className="flex flex-wrap gap-4 mb-4 text-sm">
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-emerald-500"></div>
              <span className="text-slate-600">{stats.active} Active</span>
            </div>
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-purple-500"></div>
              <span className="text-slate-600">{stats.virtual} Virtual</span>
            </div>
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-blue-500"></div>
              <span className="text-slate-600">{stats.physical} Physical</span>
            </div>
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-slate-300"></div>
              <span className="text-slate-600">{stats.reserved} Reserved</span>
            </div>
            <button
              onClick={() => setShowFreeIPs(!showFreeIPs)}
              className={`flex items-center gap-2 px-3 py-1 rounded-full transition-colors ${
                showFreeIPs
                  ? 'bg-emerald-100 text-emerald-800 ring-2 ring-emerald-300'
                  : 'bg-emerald-50 text-emerald-700 hover:bg-emerald-100'
              }`}
            >
              <CircleDot className="w-3 h-3" />
              <span className="font-medium">{stats.freeStatic} Free Static</span>
              {showFreeIPs ? <ChevronUp className="w-3 h-3" /> : <ChevronDown className="w-3 h-3" />}
            </button>
          </div>

          {/* Free Static IPs Panel */}
          {showFreeIPs && (
            <div className="mb-4 p-4 bg-emerald-50 border border-emerald-200 rounded-xl">
              <div className="flex items-center justify-between mb-3">
                <h3 className="font-semibold text-emerald-800 flex items-center gap-2">
                  <CircleDot className="w-4 h-4" />
                  {freeStaticIPs.length} Free Static IP Addresses
                  <span className="text-xs font-normal text-emerald-600">(.171–.254 range)</span>
                </h3>
                <span className="text-xs text-emerald-600">Click any IP to copy</span>
              </div>

              {/* Ranges summary */}
              <div className="mb-3 text-sm text-emerald-700">
                <span className="font-medium">Available ranges: </span>
                {freeIPRanges.map((range, idx) => (
                  <span key={idx}>
                    {range.start === range.end
                      ? `.${range.start}`
                      : `.${range.start}–.${range.end}`}
                    {idx < freeIPRanges.length - 1 ? ', ' : ''}
                  </span>
                ))}
              </div>

              {/* Individual IPs grid */}
              <div className="flex flex-wrap gap-2 max-h-48 overflow-y-auto">
                {freeStaticIPs.map(ip => (
                  <button
                    key={ip}
                    onClick={() => copyToClipboard(ip)}
                    className={`px-2 py-1 font-mono text-xs rounded transition-all ${
                      copiedIP === ip
                        ? 'bg-emerald-500 text-white'
                        : 'bg-white text-emerald-700 hover:bg-emerald-100 border border-emerald-200'
                    }`}
                  >
                    {copiedIP === ip ? (
                      <span className="flex items-center gap-1">
                        <Check className="w-3 h-3" /> Copied
                      </span>
                    ) : (
                      ip.replace('192.168.0.', '.')
                    )}
                  </button>
                ))}
              </div>

              {/* Quick pick */}
              <div className="mt-3 pt-3 border-t border-emerald-200">
                <span className="text-sm text-emerald-700">Next available static: </span>
                <button
                  onClick={() => copyToClipboard(freeStaticIPs[0])}
                  className="font-mono text-sm font-semibold text-emerald-800 hover:underline"
                >
                  {freeStaticIPs[0]}
                </button>
                {freeStaticIPs.length > 1 && (
                  <>
                    <span className="text-emerald-600 mx-2">or</span>
                    <button
                      onClick={() => copyToClipboard(freeStaticIPs[freeStaticIPs.length - 1])}
                      className="font-mono text-sm font-semibold text-emerald-800 hover:underline"
                    >
                      {freeStaticIPs[freeStaticIPs.length - 1]}
                    </button>
                    <span className="text-xs text-emerald-600 ml-2">(highest)</span>
                  </>
                )}
              </div>
            </div>
          )}

          {/* Search and Filters */}
          <div className="flex flex-wrap gap-3 items-center">
            <div className="relative flex-1 min-w-64">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
              <input
                type="text"
                placeholder="Search IP, hostname, service, or location..."
