    staticAssigned: staticAssigned.length,
    dhcpPoolSize: NETWORK_CONFIG.dhcpEnd - NETWORK_CONFIG.dhcpStart + 1 - NETWORK_CONFIG.fixedInDHCP.length,
  };
}, [freeStaticIPs]);

