              {showFreeIPs ? <ChevronUp className="w-3 h-3" /> : <ChevronDown className="w-3 h-3" />}
            </button>
          </div>

          {/* Free Static IPs Panel */}
          {showFreeIPs && (
            <div className="mb-4 p-4 bg-emerald-50 border border-emerald-200 rounded-xl">
              <div className="flex items-center justify-between mb-3">
                <h3 className="font-semibold text-emerald-800 flex items-center gap-2">
                  <CircleDot className="w-4 h-4" />
                  {freeStaticIPs.length} Free Static IP Addresses
                  <span className="text-xs font-normal text-emerald-600">(.171–.254 range)</span>
                </h3>
                <span className="text-xs text-emerald-600">Click any IP to copy</span>
              </div>

              {/* Ranges summary */}
              <div className="mb-3 text-sm text-emerald-700">
                <span className="font-medium">Available ranges: </span>
                {freeIPRanges.map((range, idx) => (
                  <span key={idx}>
                    {range.start === range.end
                      ? `.${range.start}`
                      : `.${range.start}–.${range.end}`}
                    {idx < freeIPRanges.length - 1 ? ', ' : ''}
                  </span>
                ))}
              </div>

              {/* Individual IPs grid */}
              <div className="flex flex-wrap gap-2 max-h-48 overflow-y-auto">
                {freeStaticIPs.map(ip => (
                  <button
                    key={ip}
                    onClick={() => copyToClipboard(ip)}
                    className={`px-2 py-1 font-mono text-xs rounded transition-all ${
                      copiedIP === ip
                        ? 'bg-emerald-500 text-white'
                        : 'bg-white text-emerald-700 hover:bg-emerald-100 border border-emerald-200'
                    }`}
                  >
                    {copiedIP === ip ? (
                      <span className="flex items-center gap-1">
                        <Check className="w-3 h-3" /> Copied
                      </span>
                    ) : (
                      ip.replace('192.168.0.', '.')
                    )}
                  </button>
                ))}
              </div>

              {/* Quick pick */}
              <div className="mt-3 pt-3 border-t border-emerald-200">
                <span className="text-sm text-emerald-700">Next available static: </span>
                <button
                  onClick={() => copyToClipboard(freeStaticIPs[0])}
                  className="font-mono text-sm font-semibold text-emerald-800 hover:underline"
                >
                  {freeStaticIPs[0]}
                </button>
                {freeStaticIPs.length > 1 && (
                  <>
                    <span className="text-emerald-600 mx-2">or</span>
                    <button
                      onClick={() => copyToClipboard(freeStaticIPs[freeStaticIPs.length - 1])}
                      className="font-mono text-sm font-semibold text-emerald-800 hover:underline"
                    >
                      {freeStaticIPs[freeStaticIPs.length - 1]}
                    </button>
                    <span className="text-xs text-emerald-600 ml-2">(highest)</span>
                  </>
                )}
              </div>
            </div>
          )}

          {/* Search and Filters */}
          <div className="flex flex-wrap gap-3 items-center">
            <div className="relative flex-1 min-w-64">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
              <input
                type="text"
                placeholder="Search IP, hostname, service, or location..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-slate-400 focus:border-transparent text-sm"
              />
            </div>

            <select
              value={selectedType}
              onChange={(e) => setSelectedType(e.target.value)}
              className="px-3 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-slate-400 text-sm bg-white"
            >
              <option value="">All Types</option>
              {types.map(type => (
                <option key={type} value={type}>{type}</option>
              ))}
            </select>

            <select
              value={selectedLocation}
              onChange={(e) => setSelectedLocation(e.target.value)}
              className="px-3 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-slate-400 text-sm bg-white"
            >
              <option value="">All Locations</option>
              {locations.map(loc => (
                <option key={loc} value={loc}>{loc}</option>
              ))}
            </select>

            <label className="flex items-center gap-2 text-sm text-slate-600 cursor-pointer">
              <input
                type="checkbox"
                checked={showReserved}
                onChange={(e) => setShowReserved(e.target.checked)}
                className="w-4 h-4 rounded border-slate-300 text-slate-600 focus:ring-slate-400"
              />
              Show Reserved
            </label>

            {hasActiveFilters && (
              <button
                onClick={clearFilters}
                className="flex items-center gap-1 px-3 py-2 text-sm text-slate-500 hover:text-slate-700 hover:bg-slate-100 rounded-lg transition-colors"
              >
                <X className="w-4 h-4" />
                Clear
              </button>
            )}
          </div>
        </div>
      </div>

      {/* Results Count */}
      <div className="max-w-7xl mx-auto px-4 py-3">
        <p className="text-sm text-slate-500">
          Showing {filteredData.length} of {showReserved ? ipData.length : stats.active} addresses
        </p>
      </div>

      {/* Content */}
      <div className="max-w-7xl mx-auto px-4 pb-8">
        {viewMode === 'cards' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {filteredData.map((item, index) => {
              const Icon = getServiceIcon(item.apps, item.assetName);
              const isExpanded = expandedCard === index;
              const isReserved = item.assetName === 'Reserved';
              const isFree = item.assetName === 'Free';
              const isDHCP = isInDHCPRange(item.ip);
              const isFixed = isFixedInDHCP(item.ip);

              return (
                <div
                  key={item.ip}
                  onClick={() => !isFree && setExpandedCard(isExpanded ? null : index)}
