   112→// Free IPs are explicitly marked in the spreadsheet (green highlighted)
   113→// These are the only IPs available for new assignments
   114→const getFreeIPs = () => NETWORK_CONFIG.freeIPs;
   115→
   116→// Check if an IP is marked as free
   117→const isFreeIP = (ip) => NETWORK_CONFIG.freeIPs.includes(ip);
   118→
   119→// Group consecutive IPs into ranges for cleaner display
   120→const groupIPsIntoRanges = (ips) => {
   121→  if (ips.length === 0) return [];
   122→
   123→  const ranges = [];
   124→  let rangeStart = parseInt(ips[0].split('.')[3]);
   125→  let rangeEnd = rangeStart;
   126→
   127→  for (let i = 1; i < ips.length; i++) {
   128→    const current = parseInt(ips[i].split('.')[3]);
   129→    if (current === rangeEnd + 1) {
   130→      rangeEnd = current;
   131→    } else {
   132→      ranges.push({ start: rangeStart, end: rangeEnd });
   133→      rangeStart = current;
   134→      rangeEnd = current;
   135→    }
   136→  }
   137→  ranges.push({ start: rangeStart, end: rangeEnd });
   138→
   139→  return ranges;
   140→};
   141→
   142→// Get unique values for filters
   143→const getUniqueValues = (data, key) => {
   144→  const values = [...new Set(data.map(item => item[key]).filter(Boolean))];
   145→  return values.sort();
   146→};
   147→
   148→// Get icon for app/service type
   149→const getServiceIcon = (apps, assetName) => {
   150→  const combined = `${apps} ${assetName}`.toLowerCase();
   151→  if (combined.includes('camera') || combined.includes('reolink') || combined.includes('tapo')) return Camera;
   152→  if (combined.includes('proxmox')) return Server;
   153→  if (combined.includes('docker')) return Box;
   154→  if (combined.includes('pihole') || combined.includes('dns')) return Shield;
   155→  if (combined.includes('nas') || combined.includes('truenas') || combined.includes('synology')) return HardDrive;
   156→  if (combined.includes('unifi') || combined.includes('wifi') || combined.includes('access point')) return Wifi;
   157→  if (combined.includes('ghost') || combined.includes('blog') || combined.includes('nginx')) return Globe;
   158→  if (combined.includes('switch') || combined.includes('mikrotik') || combined.includes('netgear')) return Monitor;
   159→  return Cpu;
   160→};
