   187→// Check if IP is in DHCP range
   188→const isInDHCPRange = (ip) => {
   189→  const lastOctet = parseInt(ip.split('.')[3]);
   190→  return lastOctet >= NETWORK_CONFIG.dhcpStart && lastOctet <= NETWORK_CONFIG.dhcpEnd;
   191→};
   192→
   193→// Check if IP is a fixed address within DHCP range
   194→const isFixedInDHCP = (ip) => {
   195→  const lastOctet = parseInt(ip.split('.')[3]);
   196→  return NETWORK_CONFIG.fixedInDHCP.includes(lastOctet);
