                          {item.location && (
                            <span className={`px-2 py-0.5 text-xs font-medium rounded-full ${getLocationColor(item.location)}`}>
                              {item.location}
                            </span>
                          )}
                        </td>
                        <td className="px-4 py-3 text-sm text-slate-600">{item.apps || '—'}</td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
