  const handleSaveItem = (updatedItem) => {
    setIpData(prev => prev.map(item =>
      item.ip === updatedItem.ip ? updatedItem : item
    ));
    setHasChanges(true);
    setEditingItem(null);
    setExpandedCard(null);
  };

  const handleMarkFree = (ip) => {
    setIpData(prev => prev.map(item =>
      item.ip === ip
        ? { ...item, assetName: 'Free', hostname: '', type: '', location: '', apps: '' }
