              ) : (
                <p className="text-emerald-700 text-sm">No free static IPs available. Release an IP to make it available.</p>
              )}
            </div>
          )}

          {/* Search and Filters */}
          <div className="flex flex-wrap gap-3 items-center">
            <div className="relative flex-1 min-w-64">
